<?php declare(strict_types=1);
namespace App\Services;
use App\Constants\VideoStatus;use App\Repositories\VideoRepository;
final class VideoService { public function __construct(private VideoRepository $videos,private LogService $log){} public function all():array{return $this->videos->all();} public function upload(array $file):void{if(($file['error']??UPLOAD_ERR_NO_FILE)!==UPLOAD_ERR_OK)throw new \InvalidArgumentException('Video upload failed.');if(($file['size']??0)>config('settings.max_upload_bytes'))throw new \InvalidArgumentException('Video exceeds configured upload limit.');$mime=(new \finfo(FILEINFO_MIME_TYPE))->file($file['tmp_name']);if(!in_array($mime,config('settings.allowed_video_mimes'),true))throw new \InvalidArgumentException('Unsupported video type.');$dir=config('settings.upload_directory');if(!is_dir($dir))mkdir($dir,0750,true);$name=bin2hex(random_bytes(16)).'.'.strtolower(pathinfo($file['name'],PATHINFO_EXTENSION));if(!move_uploaded_file($file['tmp_name'],$dir.'/'.$name))throw new \RuntimeException('Unable to store uploaded video.');$this->videos->create(['title'=>pathinfo($file['name'],PATHINFO_FILENAME),'filename'=>$name,'original_filename'=>$file['name'],'mime_type'=>$mime,'size_bytes'=>$file['size'],'status'=>VideoStatus::READY]);$this->log->info('Video uploaded',['original_filename'=>$file['name']]);} public function rename(int $id,string $title):void{if(trim($title)==='')throw new \InvalidArgumentException('Video name is required.');$this->videos->rename($id,trim($title));} public function delete(int $id):void{$video=$this->videos->find($id);if(!$video)throw new \InvalidArgumentException('Video not found.');$this->videos->deleteWithReferences($id);foreach([$video['filename'],$video['thumbnail_filename']??null]as$file)if($file&&is_file(config('settings.upload_directory').'/'.$file))unlink(config('settings.upload_directory').'/'.$file);$this->log->info('Video deleted',['id'=>$id]);} }
